import React from 'react';
import './App.css';

// 1. İLETİŞİM FORMU BİLEŞENİ (App'in dışında tanımlıyoruz)
const Contact = () => {
  const handleSubmit = (e) => {
    e.preventDefault();
    alert("Form gönderildi!");
  };

  return (
    <section id="contact">
      <div className="contact-form">
        <h2>CONTACT</h2>
        <form onSubmit={handleSubmit}>
          <div className="input-group">
            <label htmlFor="fname">First Name</label>
            <input type="text" name="firstname" id="fname" placeholder="Type your name" required />
          </div>
          <div className="input-group">
            <label htmlFor="email">Email</label>
            <input type="email" name="email" id="email" required />
          </div>
          <div className="input-group">
            <label htmlFor="message">Your message</label>
            <textarea id="message" name="message" required placeholder="Typ..."></textarea>
          </div>
          <input className="submit-btn" type="submit" value="Submit" />
        </form>
      </div>
    </section>
  );
};

// 2. ANA UYGULAMA
function App() {
  return (
    <div className="App">
      <header>
        <div className="top-bar">
          <nav>
            <ul>
              <li><a href="#" className="active">HOME</a></li>
              <li><a href="#">ABOUT</a></li>
              <li><a href="#">PROJECTS</a></li>
              <li><a href="#">CONTACT</a></li>
            </ul>
          </nav>
        </div>
        <div className="hero-content">
          <h1>Hello, I'm Cesim</h1>
        </div>
      </header>

      <main>
        {/* Senin diğer bölümlerin buraya gelecek */}
        <div className="content-wrapper">
           <p>Burada yetenekler ve projeler olacak...</p>
        </div>

        {/* İŞTE BURASI ÖNEMLİ: Yukarıdaki Contact bileşenini burada çağırıyoruz */}
        <Contact />
      </main>

      <footer>
        <p>© 2026 Cesim Portfolio</p>
      </footer>
    </div>
  );
}

export default App;
